/// C: `static int num2straux(char *buff, int sz, lua_Number x)`
fn num2straux(x: f64) -> Vec<u8> {
    if x.is_nan() || x.is_infinite() {
        // C: return l_sprintf(buff, sz, LUA_NUMBER_FMT, x);
